// =============================================
// v5: inline base64 (≤ 20MB) + Gemini File API (> 20MB)
// 小檔用 inline，大檔先上傳再引用，上限 2GB
// =============================================

const item = $input.first().json;
const { queue_item_id, platform, video_id, video_url, title, author_name, _config: C } = item;

async function runSQL(sql) {
  return await this.helpers.httpRequest({
    method: 'POST',
    url: C.SQL_WEBHOOK,
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({ sql }),
    json: true,
  });
}

async function updateStatus(status, scriptRaw, timecodes) {
  const sets = [`status = '${status}'`];
  if (scriptRaw != null) {
    sets.push(`script_raw = '${String(scriptRaw).replace(/'/g, "''")}'`);
  }
  if (timecodes != null) {
    sets.push(`script_timecodes = '${JSON.stringify(timecodes).replace(/'/g, "''")}'::jsonb`);
  }
  if (status === 'completed') {
    sets.push(`script_generated_at = NOW()`);
  }
  await runSQL.call(this, `UPDATE viral_benchmark.shoot_queue SET ${sets.join(', ')} WHERE id = '${queue_item_id}'`);
}

function fail(msg) {
  return [{ json: { queue_item_id, title: title || '\u672A\u77E5\u5F71\u7247', platform, status: 'failed', error: msg, _config: C } }];
}

// === Gemini File API: 上傳大檔影片 ===
async function uploadToGeminiFileAPI(videoBuffer) {
  const numBytes = videoBuffer.length;
  // Step A: 啟動 resumable upload
  const startRes = await this.helpers.httpRequest({
    method: 'POST',
    url: `https://generativelanguage.googleapis.com/upload/v1beta/files?key=${C.GEMINI_KEY}`,
    headers: {
      'X-Goog-Upload-Protocol': 'resumable',
      'X-Goog-Upload-Command': 'start',
      'X-Goog-Upload-Header-Content-Length': String(numBytes),
      'X-Goog-Upload-Header-Content-Type': 'video/mp4',
      'Content-Type': 'application/json',
    },
    body: JSON.stringify({ file: { display_name: `video_${queue_item_id}` } }),
    returnFullResponse: true,
  });
  const uploadUrl = startRes.headers['x-goog-upload-url'];
  if (!uploadUrl) throw new Error('\u7121\u6CD5\u53D6\u5F97 Gemini File API upload URL');

  // Step B: 上傳檔\u6848
  const uploadRes = await this.helpers.httpRequest({
    method: 'POST',
    url: uploadUrl,
    headers: {
      'Content-Length': String(numBytes),
      'X-Goog-Upload-Offset': '0',
      'X-Goog-Upload-Command': 'upload, finalize',
    },
    body: videoBuffer,
    json: true,
    timeout: 300000,
  });
  const fileUri = uploadRes?.file?.uri;
  const fileName = uploadRes?.file?.name;
  if (!fileUri) throw new Error('Gemini File API \u4E0A\u50B3\u5931\u6557\uFF0C\u7121 file URI');

  // Step C: \u7B49\u5F85\u8655\u7406\u5B8C\u6210 (polling)
  let state = uploadRes?.file?.state || 'PROCESSING';
  let attempts = 0;
  while (state === 'PROCESSING' && attempts < 60) {
    await new Promise(r => setTimeout(r, 5000));
    const statusRes = await this.helpers.httpRequest({
      method: 'GET',
      url: `https://generativelanguage.googleapis.com/v1beta/${fileName}?key=${C.GEMINI_KEY}`,
      json: true,
    });
    state = statusRes?.state || 'PROCESSING';
    attempts++;
  }
  if (state !== 'ACTIVE') {
    throw new Error(`Gemini File API \u6A94\u6848\u8655\u7406\u903E\u6642\u6216\u5931\u6557 (state=${state}, attempts=${attempts})`);
  }
  return fileUri;
}

try {
  // === Step 1: TikHub \u53D6\u5F97\u4E0B\u8F09 URL ===
  let downloadUrl = null;
  if (platform === 'douyin' || platform === 'tiktok') {
    const apiPath = platform === 'douyin'
      ? '/api/v1/douyin/app/v3/fetch_one_video'
      : '/api/v1/tiktok/app/v3/fetch_one_video';
    try {
      const tikJson = await this.helpers.httpRequest({
        method: 'GET',
        url: `${C.TIKHUB_BASE}${apiPath}?aweme_id=${video_id}`,
        headers: { Authorization: `Bearer ${C.TIKHUB_KEY}`, Accept: 'application/json' },
        json: true,
      });
      if (tikJson && tikJson.code === 200) {
        const aweme = tikJson.data?.aweme_detail || tikJson.data;
        downloadUrl = aweme?.video?.play_addr?.url_list?.[0]
          || aweme?.video?.play_addr_h264?.url_list?.[0]
          || aweme?.video?.play_addr_lowbr?.url_list?.[0]
          || aweme?.video?.download_addr?.url_list?.[0]
          || null;
      }
    } catch (e) { /* TikHub error */ }
  }
  if (!downloadUrl) {
    const pn = platform === 'douyin' ? '\u6296\u97F3' : platform === 'tiktok' ? 'TikTok' : '\u5C0F\u7D05\u66F8';
    const errMsg = `\u7121\u6CD5\u53D6\u5F97\u5F71\u7247\u4E0B\u8F09\u9023\u7D50\uFF08${pn}\uFF09`;
    await updateStatus.call(this, 'failed', errMsg);
    return fail(errMsg);
  }

  // === Step 2: \u4E0B\u8F09\u5F71\u7247 ===
  let videoBuffer;
  try {
    videoBuffer = await this.helpers.httpRequest({
      method: 'GET',
      url: downloadUrl,
      headers: {
        'User-Agent': 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36',
        'Referer': 'https://www.douyin.com/',
      },
      encoding: 'arraybuffer',
      timeout: 300000,
    });
  } catch (e) {
    const errMsg = `\u5F71\u7247\u4E0B\u8F09\u5931\u6557: ${e.message}`;
    await updateStatus.call(this, 'failed', errMsg);
    return fail(errMsg);
  }
  if (!Buffer.isBuffer(videoBuffer)) {
    videoBuffer = Buffer.from(videoBuffer);
  }
  const numBytes = videoBuffer.length;
  const sizeMB = (numBytes / 1024 / 1024).toFixed(1);
  if (numBytes < 10240) {
    const errMsg = `\u5F71\u7247\u6A94\u6848\u592A\u5C0F\uFF08${numBytes} bytes\uFF09`;
    await updateStatus.call(this, 'failed', errMsg);
    return fail(errMsg);
  }
  // \u4E0A\u9650 200MB\uFF08\u5B89\u5168\u7DE9\u885D\uFF0C\u5BE6\u969B File API \u652F\u63F4 2GB\uFF09
  if (numBytes > 200 * 1024 * 1024) {
    const errMsg = `\u5F71\u7247\u8D85\u904E 200MB\uFF08${sizeMB}MB\uFF09\uFF0C\u7121\u6CD5\u8655\u7406`;
    await updateStatus.call(this, 'failed', errMsg);
    return fail(errMsg);
  }

  // === Step 3: \u6839\u64DA\u5927\u5C0F\u9078\u64C7\u4E0A\u50B3\u65B9\u5F0F ===
  const INLINE_LIMIT = 20 * 1024 * 1024; // 20MB
  let videoPart;
  let uploadMethod;

  if (numBytes <= INLINE_LIMIT) {
    // \u5C0F\u6A94: inline base64
    uploadMethod = 'inline';
    const videoBase64 = videoBuffer.toString('base64');
    videoPart = { inline_data: { mime_type: 'video/mp4', data: videoBase64 } };
  } else {
    // \u5927\u6A94: Gemini File API
    uploadMethod = 'file_api';
    const fileUri = await uploadToGeminiFileAPI.call(this, videoBuffer);
    videoPart = { file_data: { mime_type: 'video/mp4', file_uri: fileUri } };
  }

  const PROMPT = '\u4F60\u662F\u4E00\u4F4D\u5C08\u696D\u7684\u5F71\u7247\u9010\u5B57\u7A3F\u8F49\u9304\u54E1\u3002\n\n## \u4EFB\u52D9\n\u8ACB\u4ED4\u7D30\u89C0\u770B\u4E26\u8046\u807D\u9019\u652F\u5F71\u7247\uFF0C\u7522\u51FA **1:1 \u5B8C\u5168\u9084\u539F** \u7684\u9010\u5B57\u7A3F\u3002\n\n## \u56B4\u683C\u8981\u6C42\n1. **dialogue \u6B04\u4F4D\u5FC5\u9808\u662F\u5F71\u7247\u4E2D\u5BE6\u969B\u8AAA\u51FA\u7684\u6BCF\u4E00\u53E5\u8A71**\uFF0C\u4E00\u5B57\u4E0D\u6F0F\u3001\u4E00\u5B57\u4E0D\u6539\u3001\u4E0D\u8981\u6F64\u98FE\u3001\u4E0D\u8981\u6539\u5BEB\u3001\u4E0D\u8981\u6458\u8981\n2. \u5982\u679C\u5F71\u7247\u4E2D\u6709\u80CC\u666F\u97F3\u6A02\u4F46\u6C92\u6709\u4EBA\u8AAA\u8A71\uFF0Cdialogue \u586B\u300C\uFF08\u7121\u5C0D\u8A71\uFF09\u300D\n3. \u5982\u679C\u5F71\u7247\u4E2D\u6709\u756B\u9762\u6587\u5B57\uFF08\u5B57\u5361\u3001\u5B57\u5E55\uFF09\uFF0C\u5728 scene \u4E2D\u5B8C\u6574\u8A18\u9304\n4. scene \u6B04\u4F4D\u63CF\u8FF0\u4F60\u300C\u5BE6\u969B\u770B\u5230\u7684\u756B\u9762\u300D\uFF0C\u4E0D\u662F\u4F60\u63A8\u6E2C\u7684\n5. note \u6B04\u4F4D\u8A18\u9304\u8A72\u7247\u6BB5\u7684\u62CD\u651D\u624B\u6CD5\u6216\u7279\u6B8A\u6548\u679C\uFF08\u8F49\u5834\u3001\u6FFE\u93E1\u3001\u7279\u6548\u6587\u5B57\u7B49\uFF09\n6. **\u5FC5\u9808\u4F7F\u7528\u7E41\u9AD4\u4E2D\u6587\u8F38\u51FA**\uFF08\u5373\u4F7F\u539F\u59CB\u5F71\u7247\u662F\u7C21\u9AD4\u4E2D\u6587\u6216\u5176\u4ED6\u8A9E\u8A00\uFF0C\u4E5F\u8981\u8F49\u70BA\u7E41\u9AD4\u4E2D\u6587\uFF09\n7. \u6642\u9593\u78BC\u5FC5\u9808\u7CBE\u6E96\u5C0D\u61C9\u5F71\u7247\u7684\u5BE6\u969B\u6642\u9593\u8EF8\n\n## \u8F38\u51FA\u683C\u5F0F\n\u76F4\u63A5\u8F38\u51FA JSON \u9663\u5217\uFF0C\u4E0D\u8981\u7528 markdown code block \u5305\u88DD\uFF0C\u4E0D\u8981\u52A0\u4EFB\u4F55\u8AAA\u660E\u6587\u5B57\uFF1A\n[{"timecode": "00:00-00:03", "scene": "\u756B\u9762", "dialogue": "\u5C0D\u8A71", "note": "\u5099\u8A3B"}]';

  let geminiJson;
  try {
    geminiJson = await this.helpers.httpRequest({
      method: 'POST',
      url: `https://generativelanguage.googleapis.com/v1beta/models/${C.GEMINI_MODEL}:generateContent?key=${C.GEMINI_KEY}`,
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({
        contents: [{
          parts: [
            videoPart,
            { text: PROMPT }
          ]
        }],
        generationConfig: { temperature: 0.2, maxOutputTokens: 8192 },
      }),
      json: true,
      timeout: 300000,
    });
  } catch (e) {
    const errMsg = `Gemini API \u932F\u8AA4 (${uploadMethod}, ${sizeMB}MB): ${e.message}`;
    await updateStatus.call(this, 'failed', errMsg);
    return fail(errMsg);
  }

  const raw = geminiJson?.candidates?.[0]?.content?.parts?.[0]?.text || '';
  if (!raw) {
    const blockReason = geminiJson?.promptFeedback?.blockReason || '';
    const finishReason = geminiJson?.candidates?.[0]?.finishReason || '';
    const errMsg = `Gemini \u56DE\u50B3\u7A7A\u767D (block=${blockReason}, finish=${finishReason}, method=${uploadMethod}, ${sizeMB}MB)`;
    await updateStatus.call(this, 'failed', errMsg);
    return fail(errMsg);
  }

  // === Step 4: \u89E3\u6790 JSON ===
  let timecodes = [];
  try { const m = raw.match(/\[[\s\S]*\]/); if (m) timecodes = JSON.parse(m[0]); } catch {}
  if (!timecodes.length) { try { const m = raw.match(/```(?:json)?\s*([\s\S]*?)```/); if (m) timecodes = JSON.parse(m[1].trim()); } catch {} }
  if (Array.isArray(timecodes) && timecodes.length > 0) {
    timecodes = timecodes.map(tc => ({
      timecode: tc.timecode||tc.time||'',
      scene: tc.scene||tc.visual||tc.description||'',
      dialogue: tc.dialogue||tc.script||tc.text||'',
      note: tc.note||tc.remark||''
    }));
  }
  if (!timecodes.length) {
    await updateStatus.call(this, 'failed', `\u7121\u6CD5\u89E3\u6790\u3002\u539F\u59CB: ${raw.substring(0, 500)}`);
    return fail('\u7121\u6CD5\u89E3\u6790\u9010\u5B57\u7A3F');
  }

  // === Step 5: \u5BEB\u56DE DB ===
  await updateStatus.call(this, 'completed', raw, timecodes);
  return [{ json: { queue_item_id, title: title || '\u672A\u77E5\u5F71\u7247', platform, status: 'completed', timecodes_count: timecodes.length, upload_method: uploadMethod, size_mb: sizeMB, _config: C } }];

} catch (err) {
  const errorMsg = err.message || String(err);
  try { await updateStatus.call(this, 'failed', `\u8655\u7406\u932F\u8AA4: ${errorMsg.substring(0, 500)}`); } catch {}
  return fail(errorMsg.substring(0, 200));
}

// 匯總結果 + Slack 通知
const results = $input.all().map(i => i.json);
const C = results[0]?._config || {};
const completed = results.filter(r => r.status === 'completed');
const failed = results.filter(r => r.status === 'failed');
const total = results.length;

let blocks = [];
if (failed.length === 0) {
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: `*✅ 逐字稿生成完成*\n共 ${total} 支全部成功` } });
} else if (completed.length === 0) {
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: `*⚠️ 逐字稿生成失敗*\n共 ${total} 支全部失敗` } });
} else {
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: `*📝 逐字稿生成結果*\n成功 ${completed.length} 支，失敗 ${failed.length} 支（共 ${total} 支）` } });
}
if (completed.length > 0) {
  const list = completed.map(r => {
    const e = r.platform === 'douyin' ? '🎵' : r.platform === 'tiktok' ? '📱' : '📕';
    return `${e} ${(r.title||'').substring(0,30)||'未知影片'}（${r.timecodes_count||0} 段）`;
  }).join('\n');
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: `*成功：*\n${list}` } });
}
if (failed.length > 0) {
  const list = failed.map(r => {
    const e = r.platform === 'douyin' ? '🎵' : r.platform === 'tiktok' ? '📱' : '📕';
    return `${e} ${(r.title||'').substring(0,30)||'未知影片'}\n   └ 原因：${(r.error||'未知錯誤').substring(0,120)}`;
  }).join('\n');
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: `*失敗：*\n${list}` } });
}
blocks.push({ type: 'divider' });
blocks.push({ type: 'section', text: { type: 'mrkdwn', text: `👉 <${C.SITE_URL || 'https://viral-benchmark.zeabur.app'}/shoot-queue|前往拍攝佇列查看>` } });

if (C.SLACK_TOKEN && C.SLACK_CHANNEL) {
  try {
    await this.helpers.httpRequest({
      method: 'POST',
      url: 'https://slack.com/api/chat.postMessage',
      headers: { 'Content-Type': 'application/json', 'Authorization': `Bearer ${C.SLACK_TOKEN}` },
      body: JSON.stringify({ channel: C.SLACK_CHANNEL, blocks, text: `逐字稿生成結果：成功 ${completed.length}，失敗 ${failed.length}` }),
    });
  } catch {}
}

return [{ json: { total, completed: completed.length, failed: failed.length, results } }];
